window.RIA_FORMAT_PRICE = function(n) {
  return '₹' + Number(n).toLocaleString('en-IN');
};

window.RIA_IMG = function(rel) {
  if (!rel) return '';
  if (rel.startsWith('/') || rel.startsWith('http')) return rel;
  return '/assets/images/products/' + rel;
};
